#include <iostream>
#include <vector>

using namespace std;

int main()
{
    vector<int> numbers = {10, 20, 30};

    vector<int>::iterator it1 = numbers.begin(); // the full, explicit type
    auto it2 = numbers.begin();                   // identical, far shorter

    cout << (*it1 == *it2) << endl;

    return 0;
}

